#include "launch.h"
#include "cuda_helpers.h"

int main() {
    launch(4, 1024);
    cudaDeviceSynchronize();
    cudaCheckErrors("kernel launch failed");

    launch(4, 32, 4, 32);
    cudaDeviceSynchronize();
    cudaCheckErrors("kernel launch failed");

    launch(4, 16, 4, 16, 4, 4);
    cudaDeviceSynchronize();
    cudaCheckErrors("kernel launch failed");

    return 0;
}
